    internal static FontMetricsTable GetTable(MetricFamily family, bool bold, bool italic)
        => (family, bold, italic) switch
        {
            (MetricFamily.Carlito, false, false) => CarlitoRegular,
            (MetricFamily.Carlito, true, false) => CarlitoBold,
            (MetricFamily.Carlito, false, true) => CarlitoItalic,
            (MetricFamily.Carlito, true, true) => CarlitoBoldItalic,
            (MetricFamily.LiberationSans, false, false) => LiberationSansRegular,
            (MetricFamily.LiberationSans, true, false) => LiberationSansBold,
            (MetricFamily.LiberationSans, false, true) => LiberationSansItalic,
            (MetricFamily.LiberationSans, true, true) => LiberationSansBoldItalic,
            (MetricFamily.LiberationSerif, false, false) => LiberationSerifRegular,
            (MetricFamily.LiberationSerif, true, false) => LiberationSerifBold,
            (MetricFamily.LiberationSerif, false, true) => LiberationSerifItalic,
            (MetricFamily.LiberationSerif, true, true) => LiberationSerifBoldItalic,
            (MetricFamily.LiberationMono, false, false) => LiberationMonoRegular,
            (MetricFamily.LiberationMono, true, false) => LiberationMonoBold,
            (MetricFamily.LiberationMono, false, true) => LiberationMonoItalic,
            (MetricFamily.LiberationMono, true, true) => LiberationMonoBoldItalic,
            _ => throw new System.ArgumentOutOfRangeException(nameof(family)),
        };
